const input = $input.first().json ?? {};
const body = input.body && typeof input.body === 'object' && !Array.isArray(input.body) ? input.body : input;
const toText = (value) => {
  if (value === null || value === undefined) {
    return '';
  }

  return String(value).trim();
};
const toLower = (value) => toText(value).toLowerCase();
const novuContract = {
  digest: {
    eventName: 'operator.digest.daily',
    templateKey: 'digest-daily'
  },
  reminder: {
    eventName: 'operator.followup.reminder',
    templateKey: 'followup-reminder'
  },
  escalation: {
    eventName: 'operator.escalation.raised',
    templateKey: 'escalation-raised'
  }
};
const validationErrors = [];
if (!toText(body.batchId)) {
  validationErrors.push('batchId is required');
}
if (!Array.isArray(body.items)) {
  validationErrors.push('items[] is required');
}
const snapshotAtRaw = toText(body.snapshotAt) || new Date().toISOString();
const snapshotAtDate = Number.isNaN(Date.parse(snapshotAtRaw)) ? new Date() : new Date(snapshotAtRaw);
const items = Array.isArray(body.items) ? body.items : [];
const normalizedItems = items.map((entry, index) => {
  const queueName = toText(entry.queueName) || 'Website contact follow-up queue';
  const ownerEmail = toLower(entry.ownerEmail) || 'unassigned@hylono.local';
  const followUpId = toText(entry.followUpId) || toText(entry.externalId) || `followup_${index + 1}`;
  const dueAtRaw = toText(entry.dueAt);
  const dueAtDate = dueAtRaw && !Number.isNaN(Date.parse(dueAtRaw)) ? new Date(dueAtRaw) : null;
  const dueInHours = dueAtDate ? Math.round((dueAtDate.getTime() - snapshotAtDate.getTime()) / 3600000) : null;
  const overdueHours = dueAtDate ? Math.max(0, Math.round((snapshotAtDate.getTime() - dueAtDate.getTime()) / 3600000)) : null;
  const reminderCount = Number(entry.reminderCount ?? 0);
  const priority = toLower(entry.priority) || 'routine';
  const preferredChannel = toLower(entry.preferredChannel) || 'email';
  const bookingStatus = toLower(entry.bookingStatus) || 'pending';
  const consentStatus = toLower(entry.consentStatus) || 'unknown';
  const requiresEscalation = Boolean(entry.requiresEscalation) || priority === 'high' || reminderCount >= 2 || (overdueHours !== null && overdueHours >= 24) || consentStatus === 'missing';
  const needsReminder = (overdueHours !== null && overdueHours >= 0) || consentStatus === 'missing' || bookingStatus === 'unconfirmed';
  const escalationLevel = requiresEscalation ? (priority === 'high' || consentStatus === 'missing' ? 'clinical-review' : 'operator-escalation') : needsReminder ? 'reminder' : 'monitor';
  const suggestedNotification = requiresEscalation ? novuContract.escalation : needsReminder ? novuContract.reminder : novuContract.digest;
  return {
    followUpId,
    queueName,
    ownerEmail,
    priority,
    preferredChannel,
    bookingStatus,
    consentStatus,
    reminderCount,
    dueAt: dueAtDate ? dueAtDate.toISOString() : null,
    dueInHours,
    overdueHours,
    requiresEscalation,
    needsReminder,
    escalationLevel,
    suggestedNovuEvent: suggestedNotification.eventName,
    suggestedTemplateKey: suggestedNotification.templateKey,
    patientName: toText(entry.patientName) || null,
    patientEmail: toLower(entry.patientEmail) || null,
    note: toText(entry.note) || null
  };
});
const overdueItems = normalizedItems.filter((item) => item.overdueHours !== null && item.overdueHours > 0);
const dueSoonItems = normalizedItems.filter((item) => item.dueInHours !== null && item.dueInHours >= 0 && item.dueInHours <= 4);
const escalationItems = normalizedItems.filter((item) => item.requiresEscalation);
const summarizeByKey = (source, keyName) => {
  const map = new Map();
  for (const item of source) {
    const key = item[keyName] || 'unknown';
    const current = map.get(key) || { key, total: 0, overdue: 0, escalations: 0 };
    current.total += 1;
    if (item.overdueHours !== null && item.overdueHours > 0) {
      current.overdue += 1;
    }
    if (item.requiresEscalation) {
      current.escalations += 1;
    }
    map.set(key, current);
  }
  return Array.from(map.values()).sort((left, right) => right.escalations - left.escalations || right.overdue - left.overdue || left.key.localeCompare(right.key));
};
const byQueue = summarizeByKey(normalizedItems, 'queueName');
const byOwner = summarizeByKey(normalizedItems, 'ownerEmail');
const reminders = normalizedItems
  .filter((item) => item.needsReminder)
  .sort((left, right) => (right.overdueHours ?? -999) - (left.overdueHours ?? -999))
  .slice(0, 25)
  .map((item) => ({
    followUpId: item.followUpId,
    queueName: item.queueName,
    ownerEmail: item.ownerEmail,
    escalationLevel: item.escalationLevel,
    suggestedNovuEvent: item.suggestedNovuEvent,
    suggestedTemplateKey: item.suggestedTemplateKey,
    preferredChannel: item.preferredChannel,
    dueAt: item.dueAt,
    overdueHours: item.overdueHours,
    suggestedTaskTitle: item.requiresEscalation ? `Escalate ${item.followUpId} for same-day review` : `Send reminder for ${item.followUpId}`
  }));
const escalations = escalationItems.slice(0, 25).map((item) => ({
  followUpId: item.followUpId,
  queueName: item.queueName,
  ownerEmail: item.ownerEmail,
  escalationLevel: item.escalationLevel,
  reason: item.consentStatus === 'missing' ? 'missing-consent' : item.overdueHours !== null && item.overdueHours >= 24 ? 'overdue-24h' : item.priority === 'high' ? 'priority-high' : 'manual-flag',
  suggestedNovuEvent: novuContract.escalation.eventName,
  suggestedTemplateKey: novuContract.escalation.templateKey,
  suggestedNovuTopicKey: item.queueName === 'Rental request triage queue' ? 'operator-rental-triage' : item.queueName === 'Checkout recovery queue' ? 'operator-checkout-recovery' : 'operator-intake-general'
}));
const digest = {
  headline: `${overdueItems.length} overdue follow-ups, ${escalationItems.length} escalations`,
  totalItems: normalizedItems.length,
  overdueCount: overdueItems.length,
  dueSoonCount: dueSoonItems.length,
  escalationCount: escalationItems.length,
  reminderCount: reminders.length,
  suggestedNovuEvent: novuContract.digest.eventName,
  suggestedTemplateKey: novuContract.digest.templateKey,
  byQueue,
  byOwner
};
const responseBody = {
  workflow: 'medtech_followup_digest_escalation',
  status: validationErrors.length > 0 ? 'invalid' : 'accepted',
  batchId: toText(body.batchId) || null,
  snapshotAt: snapshotAtDate.toISOString(),
  sourceSystem: toText(body.sourceSystem) || 'unknown',
  digest,
  reminders,
  escalations,
  validationErrors,
  suggestedNextSteps: [
    'Persist reminder and escalation actions in Twenty tasks or opportunity notes',
    'Trigger Novu topic-based notifications for operator visibility',
    'Run the snapshot at least once per business day before the first operator shift'
  ]
};
return [
  {
    json: {
      responseCode: validationErrors.length > 0 ? 422 : 202,
      responseBody
    }
  }
];
